@using sv_27d85489e9c9487fac5e8e8df6845b0d.Services
@inject ISettingsService SettingsService

<section class="settings-section">
    <h3>Profile</h3>

    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading…</span>
            </div>
        </div>
    }
    else if (_profile is not null)
    {
        <div class="row g-4">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label" for="displayName">Display Name</label>
                    <input id="displayName" class="form-control" @bind="_displayName" />
                </div>

                <div class="mb-3">
                    <label class="form-label" for="email">Email</label>
                    <input id="email" type="email" class="form-control" @bind="_email" />
                </div>

                <div class="mb-3">
                    <label class="form-label" for="bio">Bio</label>
                    <textarea id="bio" class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>

            <div class="col-md-4">
                <div class="avatar-preview text-center">
                    <div class="avatar-frame mb-2">
                        @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                        {
                            <img src="@_avatarUrl" alt="Avatar" class="avatar-image" />
                        }
                        else
                        {
                            <div class="avatar-placeholder">👤</div>
                        }
                    </div>
                    <label class="form-label" for="avatarUrl">Avatar URL</label>
                    <input id="avatarUrl" class="form-control form-control-sm" @bind="_avatarUrl" />
                </div>
            </div>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible mt-3" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="mt-3 d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
                Discard Changes
            </button>
        </div>
    }
</section>

@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";
    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfileAsync();
    }

    private async Task LoadProfileAsync()
    {
        _loading = true;
        try
        {
            _profile = await SettingsService.GetProfileAsync();
            ApplyProfile(_profile);
        }
        finally
        {
            _loading = false;
        }
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _bio = profile.Bio;
        _avatarUrl = profile.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _profile = updated;
            _message = "Profile saved successfully.";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save profile: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_profile is not null)
        {
            ApplyProfile(_profile);
        }
        _message = null;
    }
}

.settings-section h3 {
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.avatar-preview {
    padding: 1rem;
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 0.5rem;
}

.avatar-frame {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    overflow: hidden;
    margin: 0 auto;
    background-color: var(--bs-tertiary-bg, #f8f9fa);
    display: flex;
    align-items: center;
    justify-content: center;
}

.avatar-image {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 3rem;
}

@using sv_27d85489e9c9487fac5e8e8df6845b0d.Services
@inject ISettingsService SettingsService

<section class="settings-section">
    <h3>Notifications</h3>

    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading…</span>
            </div>
        </div>
    }
    else if (_prefs is not null)
    {
        <div class="mb-4">
            <h5>General</h5>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <div class="mb-4">
            <h5>Muted Channels</h5>
            @if (_channels.Count == 0)
            {
                <p class="text-muted">No channels available.</p>
            }
            else
            {
                <div class="list-group">
                    @foreach (var channel in _channels)
                    {
                        <label class="list-group-item d-flex align-items-center gap-2">
                            <input class="form-check-input mt-0" type="checkbox"
                                   checked="@channel.Muted"
                                   @onchange="(e) => channel.Muted = (bool)(e.Value ?? false)" />
                            <span>@channel.Name</span>
                            @if (channel.Muted)
                            {
                                <span class="badge bg-secondary ms-auto">Muted</span>
                            }
                        </label>
                    }
                </div>
            }
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible mt-3" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>
    }
</section>

@code {
    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelItem> _channels = [];
    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            _prefs = await SettingsService.GetNotificationPrefsAsync();
            _emailNotifications = _prefs.EmailNotifications;
            _pushNotifications = _prefs.PushNotifications;
            _weeklyDigest = _prefs.WeeklyDigest;
            _channels = _prefs.MutedChannels
                .Select(c => new ChannelItem { Name = c, Muted = true })
                .ToList();
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var mutedChannels = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
            var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, mutedChannels);
            await SettingsService.SaveNotificationPrefsAsync(updated);
            _prefs = updated;
            _message = "Notification preferences saved.";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save preferences: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private class ChannelItem
    {
        public string Name { get; set; } = "";
        public bool Muted { get; set; }
    }
}

@using sv_27d85489e9c9487fac5e8e8df6845b0d.Services
@inject ISettingsService SettingsService

<section class="settings-section">
    <h3>Security</h3>

    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading…</span>
            </div>
        </div>
    }
    else if (_settings is not null)
    {
        <!-- Change Password Panel -->
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center"
                 role="button" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <span>🔑 Change Password</span>
                <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (_passwordPanelOpen)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label" for="currentPassword">Current Password</label>
                        <input id="currentPassword" type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label" for="newPassword">New Password</label>
                        <input id="newPassword" type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label" for="confirmPassword">Confirm Password</label>
                        <input id="confirmPassword" type="password" class="form-control" @bind="_confirmPassword" />
                    </div>

                    @if (!string.IsNullOrEmpty(_passwordMessage))
                    {
                        <div class="alert @(_passwordIsError ? "alert-danger" : "alert-success") mt-2" role="alert">
                            @_passwordMessage
                        </div>
                    }

                    <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @if (_changingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Update Password
                    </button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="card mb-4">
            <div class="card-body d-flex align-items-center justify-content-between">
                <div>
                    <h5 class="mb-1">Two-Factor Authentication</h5>
                    <span class="badge @(_settings.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_settings.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_settings.TwoFactorEnabled" disabled
                           aria-label="Two-factor authentication status" />
                </div>
            </div>
            @if (_settings.LastPasswordChange is not null)
            {
                <div class="card-footer text-muted small">
                    Last password change: @_settings.LastPasswordChange.Value.ToString("MMMM d, yyyy")
                </div>
            }
        </div>

        <!-- Active Sessions -->
        <div class="card mb-4">
            <div class="card-header">
                <h5 class="mb-0">Active Sessions</h5>
            </div>
            <div class="table-responsive">
                <table class="table table-hover mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _settings.Sessions)
                        {
                            var isCurrent = session == _settings.Sessions.FirstOrDefault();
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-primary ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("g")</td>
                                <td>
                                    @if (!isCurrent)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>

        <!-- Revoke Confirmation Dialog -->
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop show"></div>
            <div class="modal d-block" tabindex="-1" role="dialog">
                <div class="modal-dialog modal-dialog-centered" role="document">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>
                                Are you sure you want to revoke the session on
                                <strong>@_sessionToRevoke.Device</strong> in
                                <strong>@_sessionToRevoke.Location</strong>?
                            </p>
                            <p class="text-muted small">This will sign out the device immediately.</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke" disabled="@_revoking">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                                @if (_revoking)
                                {
                                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                                }
                                Revoke
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible mt-3" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }
    }
</section>

@code {
    private SecuritySettings? _settings;
    private bool _loading = true;

    // Password change
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;
    private string? _passwordMessage;
    private bool _passwordIsError;

    // Session revoke
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    // General messages
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        await LoadSettingsAsync();
    }

    private async Task LoadSettingsAsync()
    {
        _loading = true;
        try
        {
            _settings = await SettingsService.GetSecuritySettingsAsync();
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task ChangePasswordAsync()
    {
        _passwordMessage = null;

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordMessage = "New password cannot be empty.";
            _passwordIsError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordMessage = "New password and confirmation do not match.";
            _passwordIsError = true;
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _passwordMessage = "Password updated successfully.";
            _passwordIsError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            await LoadSettingsAsync();
        }
        catch (Exception ex)
        {
            _passwordMessage = $"Failed to change password: {ex.Message}";
            _passwordIsError = true;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        _revoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _message = $"Session on {_sessionToRevoke.Device} revoked.";
            _messageIsError = false;
            _sessionToRevoke = null;
            await LoadSettingsAsync();
        }
        catch (Exception ex)
        {
            _message = $"Failed to revoke session: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _revoking = false;
        }
    }
}

.expand-icon {
    font-size: 0.75rem;
}

