@using sv_27d85489e9c9487fac5e8e8df6845b0d.Services
@inject ISettingsService SettingsService

<section class="settings-section">
    <h3>Notifications</h3>

    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading…</span>
            </div>
        </div>
    }
    else if (_prefs is not null)
    {
        <div class="mb-4">
            <h5>General</h5>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <div class="mb-4">
            <h5>Muted Channels</h5>
            @if (_channels.Count == 0)
            {
                <p class="text-muted">No channels available.</p>
            }
            else
            {
                <div class="list-group">
                    @foreach (var channel in _channels)
                    {
                        <label class="list-group-item d-flex align-items-center gap-2">
                            <input class="form-check-input mt-0" type="checkbox"
                                   checked="@channel.Muted"
                                   @onchange="(e) => channel.Muted = (bool)(e.Value ?? false)" />
                            <span>@channel.Name</span>
                            @if (channel.Muted)
                            {
                                <span class="badge bg-secondary ms-auto">Muted</span>
                            }
                        </label>
                    }
                </div>
            }
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible mt-3" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>
    }
</section>

@code {
    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelItem> _channels = [];
    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            _prefs = await SettingsService.GetNotificationPrefsAsync();
            _emailNotifications = _prefs.EmailNotifications;
            _pushNotifications = _prefs.PushNotifications;
            _weeklyDigest = _prefs.WeeklyDigest;
            _channels = _prefs.MutedChannels
                .Select(c => new ChannelItem { Name = c, Muted = true })
                .ToList();
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var mutedChannels = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
            var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, mutedChannels);
            await SettingsService.SaveNotificationPrefsAsync(updated);
            _prefs = updated;
            _message = "Notification preferences saved.";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save preferences: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private class ChannelItem
    {
        public string Name { get; set; } = "";
