@using sv_27d85489e9c9487fac5e8e8df6845b0d.Services
@inject ISettingsService SettingsService

<section class="settings-section">
    <h3>Appearance</h3>

    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading…</span>
            </div>
        </div>
    }
    else
    {
        <div class="row g-4">
            <div class="col-md-7">
                <!-- Theme -->
                <div class="mb-4">
                    <h5>Theme</h5>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="theme-@theme" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="theme-@theme">@theme</label>
                        </div>
                    }
                </div>

                <!-- Font Size -->
                <div class="mb-4">
                    <h5>Font Size</h5>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="font-@size" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="font-@size">@size</label>
                        </div>
                    }
                </div>

                <!-- Language -->
                <div class="mb-4">
                    <h5>Language</h5>
                    <select class="form-select" style="max-width: 280px;" @bind="_language">
                        <option value="en">English</option>
                        <option value="es">Español</option>
                        <option value="fr">Français</option>
                        <option value="de">Deutsch</option>
                        <option value="ja">日本語</option>
                        <option value="zh">中文</option>
                    </select>
                </div>

                <!-- Compact Mode -->
                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>
            </div>

            <!-- Live Preview -->
            <div class="col-md-5">
                <h5>Preview</h5>
                <div class="preview-box @GetPreviewThemeClass()" style="@GetPreviewFontStyle()">
                    <div class="preview-header">
                        <strong>Sample Header</strong>
                    </div>
                    <div class="preview-body @(_compactMode ? "compact" : "")">
                        <p>This is a preview of your appearance settings.</p>
                        <button class="btn btn-sm @GetPreviewButtonClass()">Sample Button</button>
                    </div>
                    <div class="preview-footer text-muted">
                        Theme: @_theme · Font: @_fontSize · @GetLanguageDisplayName()
                    </div>
                </div>
            </div>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible mt-3" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <button class="btn btn-primary mt-3" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save
        </button>
    }
</section>

@code {
    private bool _loading = true;
    private bool _saving;
    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetAppearanceAsync();
            _theme = settings.Theme;
            _fontSize = settings.FontSize;
            _language = settings.Language;
            _compactMode = settings.CompactMode;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(updated);
            _message = "Appearance settings saved.";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save appearance: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private string GetPreviewThemeClass() => _theme switch
    {
        "Dark" => "preview-dark",
        "Light" => "preview-light",
        _ => "preview-system"
    };

    private string GetPreviewFontStyle() => _fontSize switch
    {
        "Small" => "font-size: 0.8rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 0.95rem;"
    };

    private string GetPreviewButtonClass() => _theme == "Dark" ? "btn-light" : "btn-primary";

    private string GetLanguageDisplayName() => _language switch
    {
        "es" => "Español",
        "fr" => "Français",
        "de" => "Deutsch",
        "ja" => "日本語",
        "zh" => "中文",
        _ => "English"
    };
}

