.preview-box {
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.2s ease;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid var(--bs-border-color, #dee2e6);
}

.preview-body {
    padding: 1rem;
}

.preview-body.compact {
    padding: 0.5rem 1rem;
}

.preview-body.compact p {
    margin-bottom: 0.25rem;
}

.preview-footer {
    padding: 0.5rem 1rem;
    border-top: 1px solid var(--bs-border-color, #dee2e6);
    font-size: 0.8rem;
}

.preview-light {
    background-color: #ffffff;
    color: #212529;
}

.preview-light .preview-header {
    background-color: #f8f9fa;
}

.preview-dark {
    background-color: #212529;
    color: #f8f9fa;
    border-color: #495057;
}

.preview-dark .preview-header {
    background-color: #2c3034;
    border-color: #495057;
}

.preview-dark .preview-footer {
    border-color: #495057;
    color: #adb5bd !important;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #212529 50%);
    color: #212529;
}

.preview-system .preview-header {
    background-color: #f0f0f0;
}

